from collections import defaultdict

class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if len(s) != len(t):
            return False
        seen = defaultdict(int)
        for a, b in zip(s, t):
            d = (ord(b) - ord(a)) % 26
            if d == 0:
                continue
            move_needed = d + 26 * seen[d]
            seen[d] += 1
            if move_needed > k:
                return False
        return True

