class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if len(s) != len(t):
            return False
        counts = [0] * 26
        for a, b in zip(s, t):
            diff = (ord(b) - ord(a)) % 26
            if diff != 0:
                counts[diff] += 1
        for diff in range(1, 26):
            c = counts[diff]
            if c > 0 and diff + 26 * (c - 1) > k:
                return False
        return True

