var canConvertString = function(s, t, k) {
    if (s.length !== t.length) return false;
    const counts = new Array(26).fill(0);
    for (let i = 0; i < s.length; i++) {
        const diff = ((t.charCodeAt(i) - s.charCodeAt(i)) % 26 + 26) % 26;
        if (diff !== 0) counts[diff]++;
    }
    for (let diff = 1; diff < 26; diff++) {
        const c = counts[diff];
        if (c > 0 && diff + 26 * (c - 1) > k) return false;
    }
    return true;
};
